<?php declare(strict_types=1); namespace App\Http\Controllers\Payroll; use App\Http\Controllers\Controller; use App\Models\Payroll\PayrollPayment; use App\Models\Payroll\PayrollRun; use Symfony\Component\HttpFoundation\StreamedResponse; use Illuminate\View\View; class PayrollReportController extends Controller{public function index():View{return view('payroll.reports.index',['title'=>'Laporan Payroll','runs'=>PayrollRun::with('period')->latest()->paginate(15),'payments'=>PayrollPayment::latest()->limit(10)->get()]);} public function export():StreamedResponse{return response()->streamDownload(function(){echo "nomor,total_net,status\n"; PayrollRun::cursor()->each(fn($r)=>print($r->run_number.','.$r->total_net.','.$r->status."\n"));},'laporan-payroll.csv',['Content-Type'=>'text/csv']);} public function print():View{return view('payroll.reports.print',['title'=>'Print Rekap Payroll','runs'=>PayrollRun::with('period')->latest()->get()]);}}
